#include <stdio.h>
#include <stdlib.h>

#define TLB_SIZE 10

typedef struct {
 int page;
 int frame;
} TLBEntry;

TLBEntry tlb[TLB_SIZE];
int tlbIndex = 0;

void addTLBEntry(int page, int frame) {
 tlb[tlbIndex].page = page;
 tlb[tlbIndex].frame = frame;
 tlbIndex = (tlbIndex + 1) % TLB_SIZE;
}

int lookupTLB(int page) {
 for (int i = 0; i < TLB_SIZE; i++) {
 if (tlb[i].page == page) {
 return tlb[i].frame;
 }
 }
 return -1;
}

int main() {
 addTLBEntry(0, 10);
 int frame = lookupTLB(0);
 printf('%d\n', frame);
 return 0;
}
